// Mirrors backend/src/utils/payrollCalculator.js so the add-employee form can
// show a live estimate before the server confirms the final figures on save.
const PAYE_ANNUAL_BANDS = [
  { upTo: 300000, rate: 0.07 },
  { upTo: 600000, rate: 0.11 },
  { upTo: 1100000, rate: 0.15 },
  { upTo: 1600000, rate: 0.19 },
  { upTo: 3200000, rate: 0.21 },
  { upTo: Infinity, rate: 0.24 },
];
function calculateEstimatedStatutory(grossMonthly, allowancesMonthly) {
  const annualGross = (grossMonthly + allowancesMonthly) * 12;
  const cra = Math.max(200000, annualGross * 0.01) + annualGross * 0.2;
  let taxable = Math.max(0, annualGross - cra);
  let tax = 0, lower = 0;
  for (const band of PAYE_ANNUAL_BANDS) {
    if (taxable <= 0) break;
    const amountInBand = Math.min(taxable, band.upTo - lower);
    tax += amountInBand * band.rate;
    taxable -= amountInBand;
    lower = band.upTo;
  }
  return {
    tax: Math.round((tax / 12) * 100) / 100,
    pension: Math.round(grossMonthly * 0.08 * 100) / 100,
  };
}

function exportCsv(path) {
  window.open(path, '_blank');
}

function initials(name) {
  return name
    .split(/\s+/)
    .filter(Boolean)
    .slice(0, 2)
    .map((w) => w[0])
    .join('')
    .toUpperCase();
}

// ── SVG chart helpers ────────────────────────────────────────────────────

function LineChart({ data = [], seriesKeys = ['leads', 'invoices', 'contacts'], colors = ['#3b82f6', '#f59e0b', '#22c55e'], height = 160 }) {
  if (!data.length) return <div style={{ height, display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--text-muted)', fontSize: 13 }}>No activity data yet</div>;
  const W = 560; const H = height; const PAD = { t: 12, r: 8, b: 32, l: 36 };
  const cW = W - PAD.l - PAD.r; const cH = H - PAD.t - PAD.b;
  const maxVal = Math.max(1, ...seriesKeys.flatMap((k) => data.map((d) => Number(d[k] || 0))));
  const xOf = (i) => PAD.l + (i / (data.length - 1)) * cW;
  const yOf = (v) => PAD.t + (1 - v / maxVal) * cH;
  const labelStep = Math.ceil(data.length / 5);
  return (
    <svg viewBox={`0 0 ${W} ${H}`} style={{ width: '100%', height: 'auto', display: 'block' }}>
      {/* Gridlines */}
      {[0, 0.25, 0.5, 0.75, 1].map((f) => {
        const y = PAD.t + f * cH;
        return <line key={f} x1={PAD.l} y1={y} x2={W - PAD.r} y2={y} stroke="var(--border)" strokeWidth="1" />;
      })}
      {/* Y axis labels */}
      {[0, 0.5, 1].map((f) => (
        <text key={f} x={PAD.l - 4} y={PAD.t + (1 - f) * cH + 4} fontSize="9" textAnchor="end" fill="var(--text-muted)">{Math.round(f * maxVal)}</text>
      ))}
      {/* Series lines + area fills */}
      {seriesKeys.map((k, si) => {
        const pts = data.map((d, i) => `${xOf(i)},${yOf(Number(d[k] || 0))}`).join(' ');
        const area = `${xOf(0)},${PAD.t + cH} ${pts} ${xOf(data.length - 1)},${PAD.t + cH}`;
        return (
          <g key={k}>
            <polygon points={area} fill={colors[si]} fillOpacity="0.08" />
            <polyline points={pts} fill="none" stroke={colors[si]} strokeWidth="2" strokeLinejoin="round" strokeLinecap="round" />
          </g>
        );
      })}
      {/* X axis date labels */}
      {data.map((d, i) => {
        if (i % labelStep !== 0 && i !== data.length - 1) return null;
        const label = new Date(d.date).toLocaleDateString(undefined, { month: 'short', day: 'numeric' });
        return <text key={i} x={xOf(i)} y={H - 6} fontSize="9" textAnchor="middle" fill="var(--text-muted)">{label}</text>;
      })}
    </svg>
  );
}

function BarChart({ data = [] }) {
  if (!data.length) return null;
  const W = 560; const H = 140; const PAD = { t: 24, r: 8, b: 32, l: 36 };
  const cW = W - PAD.l - PAD.r; const cH = H - PAD.t - PAD.b;
  const max = Math.max(1, ...data.map((d) => d.count));
  const barW = Math.floor(cW / data.length) - 8;
  return (
    <svg viewBox={`0 0 ${W} ${H}`} style={{ width: '100%', height: 'auto', display: 'block' }}>
      {[0, 0.5, 1].map((f) => {
        const y = PAD.t + (1 - f) * cH;
        return <line key={f} x1={PAD.l} y1={y} x2={W - PAD.r} y2={y} stroke="var(--border)" strokeWidth="1" />;
      })}
      {[0, 0.5, 1].map((f) => (
        <text key={f} x={PAD.l - 4} y={PAD.t + (1 - f) * cH + 4} fontSize="9" textAnchor="end" fill="var(--text-muted)">{Math.round(f * max)}</text>
      ))}
      {data.map((d, i) => {
        const barH = Math.max(2, (d.count / max) * cH);
        const x = PAD.l + i * (cW / data.length) + 4;
        const y = PAD.t + cH - barH;
        return (
          <g key={d.module}>
            <rect x={x} y={y} width={barW} height={barH} rx="4" fill="var(--primary)" fillOpacity={0.7 + 0.3 * (d.count / max)} />
            {d.count > 0 && <text x={x + barW / 2} y={y - 4} fontSize="9" textAnchor="middle" fill="var(--primary)">{d.count}</text>}
            <text x={x + barW / 2} y={H - 4} fontSize="9" textAnchor="middle" fill="var(--text-muted)">{d.module}</text>
          </g>
        );
      })}
    </svg>
  );
}

function SearchIcon() {
  return (
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
      <circle cx="11" cy="11" r="7" />
      <line x1="21" y1="21" x2="16.6" y2="16.6" />
    </svg>
  );
}

// Shared Save/Load bar for the three Creative tools (GD Editor, Flyer Builder,
// Logo Maker) — each backs onto the same saved_designs table via a `tool` slug.
function CreativeSaveBar({ designName, setDesignName, saving, onSave, onOpenGallery, onNew, onApplyBrandKit }) {
  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '1rem', flexWrap: 'wrap' }}>
      <input className="form-input" style={{ maxWidth: 220, fontSize: '0.85rem' }} value={designName} onChange={(e) => setDesignName(e.target.value)} placeholder="Design name" />
      <Button variant="primary" size="sm" disabled={saving} loading={saving} onClick={onSave}>Save</Button>
      <Button variant="secondary" size="sm" onClick={onOpenGallery}>My Designs</Button>
      <Button variant="ghost" size="sm" onClick={onNew}>+ New</Button>
      {onApplyBrandKit && <Button variant="ghost" size="sm" onClick={onApplyBrandKit}>🎨 Apply Brand Kit</Button>}
    </div>
  );
}

function InvoiceStatusBadge({ status }) {
  const labels = {
    draft: { text: 'Draft', color: '#F5B041', bg: 'rgba(245, 176, 65, 0.16)' },
    sent: { text: 'Sent', color: '#4D93FF', bg: 'rgba(77, 147, 255, 0.14)' },
    paid: { text: 'Paid', color: '#4ADE80', bg: 'rgba(74, 222, 128, 0.16)' },
  };
  const badge = labels[status] || labels.draft;
  return (
    <span style={{ display: 'inline-flex', alignItems: 'center', gap: 6, padding: '6px 10px', borderRadius: 999, fontSize: 12, fontWeight: 700, color: badge.color, background: badge.bg, textTransform: 'uppercase' }}>
      {badge.text}
    </span>
  );
}

