  // Global keyboard shortcuts: ? helps, ⌘B billing, ⌘, account
  useEffect(() => {
    const handler = (e) => {
      if (e.metaKey || e.ctrlKey) {
        if (e.key === 'b') { e.preventDefault(); setView('billing'); return; }
        if (e.key === ',') { e.preventDefault(); setView('account'); return; }
        if (e.key === 'n' || e.key === 'f' || e.key === 'e') { e.preventDefault(); return; } // consumed by modules
        return;
      }
      if (e.key === '?' && !e.metaKey && !e.ctrlKey && !e.altKey) {
        if (e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA' || e.target.isContentEditable) return;
        setHelpOpen((v) => !v);
      }
    };
    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, []);

  const loadWorkspace = useCallback(async () => {
    setLoading(true);
    setLoadError('');
    try {
      const meRes = await apiFetch('/api/v1/auth/me');
      setUser(meRes.user);
    } catch (err) {
      // Session likely expired/revoked between the middleware check and this
      // render. Hard navigation (not router.push) so the stale session
      // cookie is guaranteed to be re-evaluated fresh rather than bouncing
      // right back here via a cached client-side render.
      window.location.href = '/login';
      return;
    }

    try {
      const modulesRes = await apiFetch('/api/v1/modules');
      setCategories(modulesRes.categories || []);
      setOrgPlan(modulesRes.plan || null);
      // Use server-computed counts that exclude tier 2 (settings) and tier 3 (admin)
      if (modulesRes.totalModules !== undefined) {
        setTotalModules(modulesRes.totalModules);
        setActiveModules(modulesRes.activeModules);
      }
    } catch (err) {
      setLoadError(err.message || 'Could not load the workspace.');
    } finally {
      setLoading(false);
    }
  }, []);

