  const filteredInvProducts = useMemo(() => {
    const q = invProductSearch.trim().toLowerCase();
    if (!q) return invProducts;
    return invProducts.filter((p) => `${p.name || ''} ${p.sku || ''} ${p.category_name || ''}`.toLowerCase().includes(q));
  }, [invProducts, invProductSearch]);

  function exportLedgerCsv(rows) {
    const header = ['Date', 'Description', 'Reference', 'Debit', 'Credit'];
    const csvRows = rows.map((e) => [e.entry_date?.slice(0, 10) || '', e.description, e.reference || '', (e.total_debit / 100).toFixed(2), (e.total_credit / 100).toFixed(2)]
      .map((v) => `"${String(v ?? '').replace(/"/g, '""')}"`).join(','));
    const csv = [header.join(','), ...csvRows].join('\n');
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url; a.download = `ledger-${new Date().toISOString().slice(0, 10)}.csv`;
    a.click();
    URL.revokeObjectURL(url);
  }

