  async function handleUpgrade(planId, planName, priceNgn) {
    if (billingWorking) return;
    setBillingWorking(true);
    try {
      const data = await apiFetch('/api/v1/billing/initiate', {
        method: 'POST',
        body: JSON.stringify({ planId, months: 1 }),
      });
      if (data.error) { showToast(data.error); return; }

      // Load Flutterwave inline script dynamically
      await new Promise((resolve, reject) => {
        if (window.FlutterwaveCheckout) { resolve(); return; }
        const s = document.createElement('script');
        s.src = 'https://checkout.flutterwave.com/v3.js';
        s.onload = resolve;
        s.onerror = reject;
        document.head.appendChild(s);
      });

      window.FlutterwaveCheckout({
        public_key: data.publicKey,
        tx_ref: data.txRef,
        amount: data.amount,
        currency: 'NGN',
        customer: { email: data.customer.email, name: data.customer.name },
        customizations: { title: 'Digitpen Hub', description: `${planName} — 1 month`, logo: '' },
        callback: async (response) => {
          if (response.status === 'successful') {
            try {
              const verifyRes = await apiFetch('/api/v1/billing/verify', {
                method: 'POST',
                body: JSON.stringify({ txId: response.transaction_id, txRef: data.txRef }),
              });
              if (verifyRes.ok) {
                setBillingSubscription(verifyRes.subscription);
                showToast(`Upgraded to ${planName}!`);
                loadBilling();
              } else {
                showToast(verifyRes.error || 'Verification failed. Contact support.');
              }
            } catch {
              showToast('Verification failed. Contact support.');
            }
          } else {
            showToast('Payment was not completed.');
          }
        },
        onclose: () => {},
      });
    } catch {
      showToast('Unable to initiate payment.');
    } finally {
      setBillingWorking(false);
    }
  }

