  function posAddToCart(product) {
    setPosCart((cart) => {
      const existing = cart.find((i) => i.productId === product.id);
      if (existing) return cart.map((i) => i.productId === product.id ? { ...i, qty: i.qty + 1 } : i);
      return [...cart, { productId: product.id, name: product.name, price: Number(product.price), qty: 1, unit: product.unit }];
    });
  }

  function posRemoveFromCart(productId) { setPosCart((c) => c.filter((i) => i.productId !== productId)); }

  async function handlePosCheckout() {
    if (!posCart.length) { showToast('Cart is empty'); return; }
    const subtotal = posCart.reduce((s, i) => s + i.price * i.qty, 0);
    const disc = Number(posDiscount) || 0;
    const total = Math.max(0, subtotal - disc);
    const data = await apiFetch('/api/v1/pos/sales', { method: 'POST', body: JSON.stringify({
      sessionId: posSession?.id, items: posCart, subtotal, discount: disc, taxRate: 0, total, paymentMethod: posPayment,
    })});
    if (data.error) { showToast(data.error); return; }
    setPosCart([]); setPosDiscount('0');
    showToast('Sale recorded');
    const [salesRes, statsRes] = await Promise.all([apiFetch('/api/v1/pos/sales'), apiFetch('/api/v1/pos/stats')]);
    setPosSales(salesRes.sales || []); setPosStats(statsRes);
  }

