  function quoteLineTotal(items, discount, taxRate) {
    const sub = (items||[]).reduce((s, i) => s + (Number(i.qty)||0) * (Number(i.unitPrice)||0), 0);
    const disc = Number(discount)||0;
    const tax = (sub - disc) * (Number(taxRate)||0) / 100;
    return { subtotal: sub, taxAmount: tax, total: sub - disc + tax };
  }

