  function fbAddField() {
    if (!fbNewField.label.trim()) return;
    const field = {
      label: fbNewField.label,
      type: fbNewField.type,
      required: fbNewField.required,
      id: `field_${Date.now()}`,
      options: fbNewField.type === 'select' || fbNewField.type === 'radio' ? fbNewField.options.split(',').map((s) => s.trim()).filter(Boolean) : [],
      showIf: fbNewField.showIfFieldId ? { fieldId: fbNewField.showIfFieldId, operator: 'equals', value: fbNewField.showIfValue } : null,
    };
    setFbDraft((d) => ({ ...d, fields: [...d.fields, field] }));
    setFbNewField(createBlankFbNewField());
  }

  function fbRemoveField(id) { setFbDraft((d) => ({ ...d, fields: d.fields.filter((f) => f.id !== id) })); }

  // A 'pagebreak' is a pseudo-field with no label/answer — it just splits the
  // fields array into steps when the public form renders, reusing the same
  // drag-reorder machinery as real fields instead of a separate paging model.
  function fbAddPageBreak() {
    setFbDraft((d) => ({ ...d, fields: [...d.fields, { id: `field_${Date.now()}`, type: 'pagebreak' }] }));
  }

  function fbUpdateFieldShowIf(id, showIf) {
    setFbDraft((d) => ({ ...d, fields: d.fields.map((f) => (f.id === id ? { ...f, showIf } : f)) }));
  }

  function fbStartEditShowIf(f) {
    setFbEditShowIfId(f.id);
    setFbEditShowIfDraft({ showIfFieldId: f.showIf ? String(f.showIf.fieldId) : '', showIfValue: f.showIf ? f.showIf.value : '' });
  }

  function fbSaveEditShowIf() {
    const showIf = fbEditShowIfDraft.showIfFieldId ? { fieldId: fbEditShowIfDraft.showIfFieldId, operator: 'equals', value: fbEditShowIfDraft.showIfValue } : null;
    fbUpdateFieldShowIf(fbEditShowIfId, showIf);
    setFbEditShowIfId(null);
  }

  function fbReorderField(dragId, dropId) {
    if (dragId == null || dropId == null || dragId === dropId) return;
    setFbDraft((d) => {
      const fields = [...d.fields];
      const from = fields.findIndex((f) => f.id === dragId);
      const to = fields.findIndex((f) => f.id === dropId);
      if (from === -1 || to === -1 || from === to) return d;
      const [moved] = fields.splice(from, 1);
      fields.splice(to, 0, moved);
      return { ...d, fields };
    });
  }

