  // Parses "name,phone,tags" CSV text (optional header row, auto-detected by
  // checking whether the first row's phone-looking column actually contains
  // digits) into contact objects ready for the bulk-import endpoint.
  function parseSmsContactsCsv(text) {
    const lines = text.split(/\r?\n/).map((l) => l.trim()).filter(Boolean);
    if (!lines.length) return [];
    const rows = lines.map((l) => l.split(',').map((c) => c.trim()));
    const looksLikeHeader = rows[0].length && !/\d/.test(rows[0][1] || '');
    const dataRows = looksLikeHeader ? rows.slice(1) : rows;
    return dataRows.map(([name, phone, tags]) => ({ name, phone, tags: tags || '' })).filter((c) => c.name && c.phone);
  }

  async function handleSmsCsvFile(e) {
    const file = e.target.files?.[0];
    if (!file) return;
    const text = await file.text();
    setSmsImportText(text);
  }

  async function handleImportSmsContacts() {
    const parsed = parseSmsContactsCsv(smsImportText);
    if (!parsed.length) { showToast('No valid rows found — expected "name,phone,tags" per line.'); return; }
    setSmsImporting(true);
    try {
      const data = await apiFetch('/api/v1/sms/contacts/bulk', { method: 'POST', body: JSON.stringify({ contacts: parsed }) });
      if (data.error) { showToast(data.error); return; }
      setSmsImportResult(data);
      const [s, c] = await Promise.all([apiFetch('/api/v1/sms/stats'), apiFetch('/api/v1/sms/contacts')]);
      setSmsStats(s); setSmsContacts(c.contacts || []);
    } finally { setSmsImporting(false); }
  }

