  function genPassword(len=16) {
    const chars='abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789!@#$%^&*()_+-=';
    return Array.from({length:len},()=>chars[Math.floor(Math.random()*chars.length)]).join('');
  }

