  // ── Creative tools — shared save/load + Brand Kit application ────────────
  // One saved_designs row per tool per design; `data` is whatever shape that
  // tool's state naturally serializes to (gdElements array, flyer field set, etc).
  async function saveCreativeDesign(tool, data) {
    setCreativeSaving(true);
    try {
      const existingId = creativeDesignId[tool];
      if (existingId) {
        const d = await apiFetch(`/api/v1/saved-designs/${existingId}`, { method: 'PUT', body: JSON.stringify({ name: creativeDesignName, data }) });
        if (d.design) showToast('Design saved!');
      } else {
        const d = await apiFetch('/api/v1/saved-designs', { method: 'POST', body: JSON.stringify({ tool, name: creativeDesignName, data }) });
        if (d.design) { setCreativeDesignId((s) => ({ ...s, [tool]: d.design.id })); showToast('Design saved!'); }
      }
      setCreativeSavedList((s) => ({ ...s, [tool]: null }));
    } catch (err) {
      showToast(err.message || 'Failed to save design.');
    } finally {
      setCreativeSaving(false);
    }
  }

  async function loadCreativeDesignsList(tool) {
    try {
      const d = await apiFetch(`/api/v1/saved-designs?tool=${tool}`);
      setCreativeSavedList((s) => ({ ...s, [tool]: d.designs || [] }));
    } catch {
      setCreativeSavedList((s) => ({ ...s, [tool]: [] }));
    }
  }

  function openCreativeGallery(tool, applyFn) {
    creativeGalleryApplyFnRef.current = applyFn;
    setCreativeGalleryOpen(tool);
    if (creativeSavedList[tool] === null) loadCreativeDesignsList(tool);
  }

  async function openCreativeDesign(tool, id) {
    try {
      const d = await apiFetch(`/api/v1/saved-designs/${id}`);
      if (d.design) {
        if (creativeGalleryApplyFnRef.current) creativeGalleryApplyFnRef.current(d.design.data || {});
        setCreativeDesignId((s) => ({ ...s, [tool]: d.design.id }));
        setCreativeDesignName(d.design.name);
        setCreativeGalleryOpen(null);
      }
    } catch (err) {
      showToast(err.message || 'Failed to load design.');
    }
  }

  async function deleteCreativeDesign(tool, id) {
    await apiFetch(`/api/v1/saved-designs/${id}`, { method: 'DELETE' });
    setCreativeSavedList((s) => ({ ...s, [tool]: (s[tool] || []).filter((x) => x.id !== id) }));
  }

  function newCreativeDesign(tool) {
    setCreativeDesignId((s) => ({ ...s, [tool]: null }));
    setCreativeDesignName('Untitled design');
  }

  async function loadBrandKitIfNeeded() {
    if (bkLoaded) return brandKit;
    await loadBrandKit();
    // loadBrandKit sets brandKit via setState, which won't be visible on this
    // synchronous return — re-fetch directly so the caller gets the value now.
    try {
      const d = await apiFetch('/api/v1/brand-kit/');
      return d.kit || null;
    } catch {
      return null;
    }
  }

  function openWebsiteBuilder() {
    setView('module');
    setActiveModuleSlug('website-builder');
    if (!pagesLoaded) loadPages().catch((e) => console.error(e));
  }

  function openPageEditor(page) {
    setEditingPage(page);
    setPageDraft({ title: page.title, slug: page.slug, metaDescription: page.meta_description || '', ogImage: page.og_image || '', canonicalUrl: page.canonical_url || '', customDomain: page.custom_domain || '', gaMeasurementId: page.ga_measurement_id || '', metaPixelId: page.meta_pixel_id || '', googleAdsConversionId: page.google_ads_conversion_id || '', status: page.status, blocks: Array.isArray(page.blocks) ? page.blocks : [] });
    setEditingBlock(null);
    setBlockDraft({});
    setPageAnalytics(null);
    apiFetch(`/api/v1/pages/${page.id}/analytics`).then(setPageAnalytics).catch((e) => console.error(e));
  }

  function reorderBlocks(dragIdx, dropIdx) {
    if (dragIdx === dropIdx || dragIdx == null || dropIdx == null) return;
    setPageDraft((d) => {
      const arr = [...d.blocks];
      const [moved] = arr.splice(dragIdx, 1);
      arr.splice(dropIdx, 0, moved);
      return { ...d, blocks: arr };
    });
  }

  function startBlankEmailCampaign() {
    setEditingCampaignId(null);
    setNewCampaign(createBlankEmailCampaign());
    setEmailFormError('');
    setShowCampaignForm(true);
  }

  function toggleBlankEmailCampaign() {
    if (showCampaignForm) {
      setShowCampaignForm(false);
      return;
    }
    startBlankEmailCampaign();
  }

  async function openEmailTemplateGallery() {
    setEmailTplGalleryOpen(true);
    setEmailTplLoading(true);
    try {
      const [catRes, listRes] = await Promise.all([
        apiFetch('/api/v1/email-templates/categories'),
        apiFetch('/api/v1/email-templates'),
      ]);
      setEmailTplCategories(catRes.categories || []);
      setEmailTplList(listRes.templates || []);
    } finally { setEmailTplLoading(false); }
  }

  async function reloadEmailTemplateList(overrides = {}) {
    setEmailTplLoading(true);
    try {
      const params = new URLSearchParams();
      const category = overrides.category !== undefined ? overrides.category : emailTplCategoryFilter;
      const q = overrides.q !== undefined ? overrides.q : emailTplSearch;
      if (category) params.set('category', category);
      if (q.trim()) params.set('q', q.trim());
      const data = await apiFetch(`/api/v1/email-templates?${params.toString()}`);
      setEmailTplList(data.templates || []);
    } finally { setEmailTplLoading(false); }
  }

  async function useEmailTemplate(id) {
    let data;
    try {
      // Create campaign from template on the backend
      const useRes = await apiFetch(`/api/v1/email-templates/${id}/use`, { method: 'POST' });
      if (useRes.campaign) {
        setEditingCampaignId(useRes.campaign.id);
        setNewCampaign({ subject: useRes.campaign.subject, previewText: useRes.campaign.preview_text || '', bodyHtml: useRes.campaign.body_html || '', listId: '' });
        setEmailTplGalleryOpen(false);
        setShowCampaignForm(true);
        showToast('Campaign created from template!');
      } else {
        // Fallback: load template data manually
        data = await apiFetch(`/api/v1/email-templates/${id}`);
        const t = data.template;
        setEditingCampaignId(null);
        setNewCampaign({ subject: t.subject, previewText: t.preview_text || '', bodyHtml: t.body_html, listId: '' });
        setEmailTplGalleryOpen(false);
        setShowCampaignForm(true);
        showToast('Template applied — customize it below before sending.');
      }
    } catch (err) {
      showToast(err.message || 'Unable to load that template.');
    }
  }

  // Plain function returning JSX, same reasoning as renderTemplateGallery / renderPexelsPicker.
  function renderEmailTemplateGallery() {
    if (!emailTplGalleryOpen) return null;
    return (
      <Modal isOpen wide title="Choose an email template" description="Pick a starting point — every field stays editable after you apply it." onClose={() => setEmailTplGalleryOpen(false)}>
        <div style={{ display: 'flex', gap: 10, marginBottom: 14, flexWrap: 'wrap' }}>
          <div style={{ flex: '1 1 220px' }}>
            <SearchInput
              value={emailTplSearch}
              onChange={(e) => setEmailTplSearch(e.target.value)}
              onKeyDown={(e) => { if (e.key === 'Enter') reloadEmailTemplateList(); }}
              placeholder="Search templates…"
            />
          </div>
          <select
            className="toolbar-select"
            value={emailTplCategoryFilter}
            onChange={(e) => { setEmailTplCategoryFilter(e.target.value); reloadEmailTemplateList({ category: e.target.value }); }}
          >
            <option value="">All categories ({emailTplCategories.reduce((s, c) => s + Number(c.count), 0)})</option>
            {emailTplCategories.map((c) => <option key={c.category} value={c.category}>{c.category} ({c.count})</option>)}
          </select>
          <Button variant="secondary" size="sm" onClick={() => reloadEmailTemplateList()}>Search</Button>
        </div>
        {emailTplLoading ? (
          <SkeletonRows rows={4} />
        ) : emailTplList.length === 0 ? (
          <EmptyState icon="✉️" title="No templates match" description="Try a different search term or category." />
        ) : (
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(220px, 1fr))', gap: 14, maxHeight: '55vh', overflowY: 'auto', padding: 2 }}>
            {emailTplList.map((t) => (
              <div key={t.id} className="card-shell" style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
                <Badge variant="neutral">{t.category}</Badge>
                <div style={{ fontWeight: 700, fontSize: '0.9rem' }}>{t.name}</div>
                <div style={{ fontSize: '0.78rem', color: 'var(--text-muted)' }}>{t.description}</div>
                <div style={{ fontSize: '0.75rem', color: 'var(--muted)', fontStyle: 'italic', borderTop: '1px solid var(--border)', paddingTop: 6 }}>&quot;{t.subject}&quot;</div>
                <Button size="sm" onClick={() => useEmailTemplate(t.id)}>Use this template</Button>
              </div>
            ))}
          </div>
        )}
      </Modal>
    );
  }

  async function searchPexels(q) {
    if (!q.trim()) { setPexelsResults([]); return; }
    setPexelsLoading(true);
    try {
      const data = await apiFetch(`/api/v1/images/search?q=${encodeURIComponent(q.trim())}&orientation=landscape`);
      setPexelsResults(data.images || []);
    } finally { setPexelsLoading(false); }
  }

  // Plain function returning JSX (not a nested component) — see Pass 1 note on
  // renderTemplateGallery for why: a component-identity remount here would
  // break the search input the same way it did there.
  function renderPexelsPicker() {
    if (!pexelsPickerOpen) return null;
    return (
      <Modal isOpen title="Search Pexels" description="Pick a free stock photo for this block." onClose={() => setPexelsPickerOpen(false)}>
        <div style={{ display: 'flex', gap: 8, marginBottom: 14 }}>
          <div style={{ flex: 1 }}>
            <SearchInput
              value={pexelsQuery}
              onChange={(e) => setPexelsQuery(e.target.value)}
              onKeyDown={(e) => { if (e.key === 'Enter') searchPexels(pexelsQuery); }}
              placeholder="e.g. gym workout, luxury interior…"
              autoFocus
            />
          </div>
          <Button size="sm" onClick={() => searchPexels(pexelsQuery)} loading={pexelsLoading}>Search</Button>
        </div>
        {pexelsResults.length === 0 ? (
          <EmptyState icon="🖼️" title={pexelsLoading ? 'Searching…' : 'Search for a photo'} description={pexelsLoading ? '' : 'Try a category or subject, like "restaurant food" or "office team".'} />
        ) : (
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(140px, 1fr))', gap: 10, maxHeight: '50vh', overflowY: 'auto' }}>
            {pexelsResults.map((img) => (
              <button
                key={img.id}
                type="button"
                onClick={() => {
                  if (pexelsTarget === 'ogImage') {
                    setPageDraft((d) => ({ ...d, ogImage: img.url }));
                  } else {
                    setBlockDraft((d) => ({ ...d, url: img.url, alt: d.alt || img.alt || '' }));
                  }
                  setPexelsPickerOpen(false);
                }}
                style={{ padding: 0, border: '1px solid var(--border)', borderRadius: 8, overflow: 'hidden', cursor: 'pointer', background: 'none' }}
              >
                <img src={img.thumbnail} alt={img.alt} style={{ width: '100%', height: 90, objectFit: 'cover', display: 'block' }} />
              </button>
            ))}
          </div>
        )}
      </Modal>
    );
  }

  async function openTemplateGallery(pageType) {
    setTplGalleryOpen(pageType);
    setTplLoading(true);
    try {
      const [catRes, listRes] = await Promise.all([
        apiFetch('/api/v1/page-templates/categories'),
        apiFetch(`/api/v1/page-templates?pageType=${pageType}`),
      ]);
      setTplCategories(catRes.categories || []);
      setTplList(listRes.templates || []);
    } finally { setTplLoading(false); }
  }

  async function reloadTemplateList(pageType, overrides = {}) {
    setTplLoading(true);
    try {
      const params = new URLSearchParams({ pageType });
      const category = overrides.category !== undefined ? overrides.category : tplCategoryFilter;
      const q = overrides.q !== undefined ? overrides.q : tplSearch;
      if (category) params.set('category', category);
      if (q.trim()) params.set('q', q.trim());
      const data = await apiFetch(`/api/v1/page-templates?${params.toString()}`);
      setTplList(data.templates || []);
    } finally { setTplLoading(false); }
  }

  async function useTemplate(templateId, source) {
    setTplUsingId(templateId);
    try {
      const data = await apiFetch(`/api/v1/page-templates/${templateId}/use`, { method: 'POST', body: JSON.stringify({}) });
      setTplGalleryOpen(false);
      setPageEditorSource(source);
      openPageEditor(data.page);
      showToast('Template applied — start customizing!');
      const listPath = data.page.page_type === 'landing' ? '/api/v1/pages?type=landing' : '/api/v1/pages?type=page';
      const fresh = await apiFetch(listPath);
      if (data.page.page_type === 'landing') setLpPages(fresh.pages || []); else setPages(fresh.pages || []);
    } catch (err) {
      showToast(err.message || 'Unable to use that template.');
    } finally { setTplUsingId(null); }
  }

  async function openSiteTemplateGallery() {
    setSiteTplGalleryOpen(true);
    setSiteTplLoading(true);
    try {
      const [catRes, listRes] = await Promise.all([
        apiFetch('/api/v1/site-templates/categories'),
        apiFetch('/api/v1/site-templates'),
      ]);
      setSiteTplCategories(catRes.categories || []);
      setSiteTplList(listRes.templates || []);
    } finally { setSiteTplLoading(false); }
  }

  async function reloadSiteTemplateList(category) {
    setSiteTplLoading(true);
    try {
      const params = category ? `?category=${encodeURIComponent(category)}` : '';
      const data = await apiFetch(`/api/v1/site-templates${params}`);
      setSiteTplList(data.templates || []);
    } finally { setSiteTplLoading(false); }
  }

  async function useSiteTemplate(templateId) {
    setSiteTplUsingId(templateId);
    try {
      const siteName = (siteTplNameDraft[templateId] || '').trim();
      const data = await apiFetch(`/api/v1/site-templates/${templateId}/use`, {
        method: 'POST',
        body: JSON.stringify(siteName ? { siteName } : {}),
      });
      setSiteTplGalleryOpen(false);
      showToast(`Site created — ${data.pages.length} linked pages ready to customize.`);
      setPageEditorSource('website-builder');
      if (data.homePage) openPageEditor(data.homePage);
      const fresh = await apiFetch('/api/v1/pages?type=page');
      setPages(fresh.pages || []);
    } catch (err) {
      showToast(err.message || 'Unable to use that site template.');
    } finally { setSiteTplUsingId(null); }
  }

  async function handleCreatePage(e) {
    e.preventDefault();
    if (!newPageTitle.trim()) return;
    const data = await apiFetch('/api/v1/pages', { method: 'POST', body: JSON.stringify({ title: newPageTitle.trim(), pageType: 'page' }) });
    if (data.error) { showToast(data.error); return; }
    setNewPageTitle('');
    setShowPageForm(false);
    const fresh = await apiFetch('/api/v1/pages?type=page');
    setPages(fresh.pages || []);
    setPageEditorSource('website-builder');
    openPageEditor(data.page);
  }

  async function handleSavePage() {
    if (!editingPage) return;
    setPagesSaving(true);
    try {
      const data = await apiFetch(`/api/v1/pages/${editingPage.id}`, {
        method: 'PUT',
        body: JSON.stringify({ title: pageDraft.title, slug: pageDraft.slug, metaDescription: pageDraft.metaDescription, ogImage: pageDraft.ogImage, canonicalUrl: pageDraft.canonicalUrl, customDomain: pageDraft.customDomain, gaMeasurementId: pageDraft.gaMeasurementId, metaPixelId: pageDraft.metaPixelId, googleAdsConversionId: pageDraft.googleAdsConversionId, status: pageDraft.status, blocks: pageDraft.blocks }),
      });
      setEditingPage(data.page);
      setPageDraft((d) => ({ ...d, ...data.page, blocks: Array.isArray(data.page.blocks) ? data.page.blocks : d.blocks }));
      const fresh = await apiFetch('/api/v1/pages?type=page');
      setPages(fresh.pages || []);
      showToast('Page saved.');
    } catch (err) {
      showToast(err.message);
    } finally {
      setPagesSaving(false);
    }
  }

  function handleDeletePage(id) { setPageConfirmDelete({ id }); }
  async function confirmPageDelete() {
    if (!pageConfirmDelete) return;
    setPageDeleting(true);
    try {
      await apiFetch(`/api/v1/pages/${pageConfirmDelete.id}`, { method: 'DELETE' });
      setPages((prev) => prev.filter((p) => p.id !== pageConfirmDelete.id));
      if (editingPage?.id === pageConfirmDelete.id) setEditingPage(null);
      showToast('Page deleted.');
    } finally { setPageDeleting(false); setPageConfirmDelete(null); }
  }

  function addBlock(type) {
    if (!type) return;
    const newBlock = { ...BLOCK_DEFAULTS[type], id: `blk_${Date.now()}` };
    setPageDraft((d) => ({ ...d, blocks: [...d.blocks, newBlock] }));
    setAddingBlockType('');
    // immediately open editor for the new block
    setEditingBlock(newBlock);
    setBlockDraft({ ...newBlock });
  }

  function moveBlock(idx, dir) {
    setPageDraft((d) => {
      const arr = [...d.blocks];
      const target = idx + dir;
      if (target < 0 || target >= arr.length) return d;
      [arr[idx], arr[target]] = [arr[target], arr[idx]];
      // keep editing the same block by updating its reference
      if (editingBlock && editingBlock.id === arr[target].id) setEditingBlock(arr[target]);
      return { ...d, blocks: arr };
    });
  }

  function deleteBlock(blockId) {
    setPageDraft((d) => ({ ...d, blocks: d.blocks.filter((b) => b.id !== blockId) }));
    if (editingBlock?.id === blockId) { setEditingBlock(null); setBlockDraft({}); }
  }

  function saveBlockDraft() {
    if (!editingBlock) return;
    setPageDraft((d) => ({
      ...d,
      blocks: d.blocks.map((b) => b.id === editingBlock.id ? { ...blockDraft } : b),
    }));
    setEditingBlock(null);
    setBlockDraft({});
  }

